// menu.js - الكود الصحيح الذي يعرض كل الكلمات
import { useState, useEffect } from "react";

export default function Menu() {
  const texts = ["مرحباً", "Bonjour", "Ciao", "Hola", "こんにちは", "你好", "안녕하세요", "नमस्ते", "Hello"];
  const [index, setIndex] = useState(0);
  const [displayChars, setDisplayChars] = useState([]);

  // دالة لتقسيم النص إلى حروف
  const splitIntoCharacters = (text) => {
    if (typeof Intl !== "undefined" && "Segmenter" in Intl) {
      const segmenter = new Intl.Segmenter("ar", { granularity: "grapheme" });
      return Array.from(segmenter.segment(text), ({ segment }) => segment);
    }
    return Array.from(text);
  };

  // دالة لإظهار الحروف بالتتابع
  const animateText = (text) => {
    const chars = splitIntoCharacters(text);
    setDisplayChars([]);
    
    chars.forEach((char, i) => {
      setTimeout(() => {
        setDisplayChars(prev => [...prev, char]);
      }, i * 50);
    });
  };

  // تغيير النص كل 2 ثانية
  useEffect(() => {
    animateText(texts[0]);
    
    const interval = setInterval(() => {
      setIndex(prev => {
        const newIndex = (prev + 1) % texts.length;
        animateText(texts[newIndex]);
        return newIndex;
      });
    }, 2000);
    
    return () => clearInterval(interval);
  }, []);

  return (
    <h1 style={{
      fontSize: "3rem",
      fontWeight: "bold",
      textAlign: "center",
      color: "white",
      background: "linear-gradient(135deg, #ffffff, #22c55e)",
      WebkitBackgroundClip: "text",
      WebkitTextFillColor: "transparent",
      padding: "20px",
      minHeight: "150px",
    }}>
      {displayChars.map((char, i) => (
        <span
          key={i}
          style={{
            display: "inline-block",
            animation: "fadeInUp 0.3s ease forwards"
          }}
        >
          {char}
        </span>
      ))}
      <style>{`
        @keyframes fadeInUp {
          from {
            opacity: 0;
            transform: translateY(20px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </h1>
  );
}
